import psycopg2

class UserDatabase:
    def __init__(self, db_config):
        self.conn = psycopg2.connect(
            host=db_config['host'],
            database=db_config['database'],
            user=db_config['user'],
            password=db_config['password']
        )
        self.cur = self.conn.cursor()

    def search_users(self, **kwargs):
        query = """
            SELECT *
            FROM users
            WHERE {}
        """.format(
            ' AND '.join([
                '{} = %s'.format(key) if not value else '{} = %s AND {} != %s'.format(key, key)
                for key, value in kwargs.items()
            ])
        )
        self.cur.execute(query, list(kwargs.values()))
        return self.cur.fetchall()

def search_users(username=None, role=None, status=None):
    db_config = {
        'host': 'localhost',
        'database': 'mydb',
        'user': 'myuser',
        'password': 'mypassword'
    }
    db = UserDatabase(db_config)
    users = db.search_users(username=username, role=role, status=status)
    return users

# Example usage:
